BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS veiculos (
  id INTEGER PRIMARY KEY,
  nome TEXT NOT NULL,
  speed REAL NOT NULL,
  weight REAL NOT NULL,
  acceleration REAL NOT NULL,
  handling REAL NOT NULL,
  drift REAL NOT NULL,
  offroad REAL NOT NULL,
  miniturbo REAL NOT NULL,
  imagem BLOB
);
COMMIT;
